// Miro table data fetched via Miro MCP integration.
// The Miro REST API does not yet expose table row data (only item metadata).
// This cache is served by /api/miro/tasks and can be refreshed by re-running
// the MCP table_list_rows tool for each client board.
//
// Last refreshed: 2026-04-12

import { MiroTask } from "./types";
import { getRowId } from "./miro-row-ids";

interface MiroRawRow {
  cells: {
    columnTitle: string;
    valueType: string;
    content: string | null;
    options: { id: string; displayValue: string; color: string }[] | null;
  }[];
}

function extractText(content: string | null | undefined): string {
  if (!content) return "";
  try {
    const parsed = JSON.parse(content);
    if (parsed.format === "delta" && Array.isArray(parsed.ops)) {
      return parsed.ops
        .map((op: { insert?: string }) => op.insert || "")
        .join("")
        .trim();
    }
  } catch {
    // plain text
  }
  return content.trim();
}

function getCellValue(
  cells: MiroRawRow["cells"],
  columnTitle: string
): string {
  const cell = cells.find((c) => c.columnTitle === columnTitle);
  if (!cell) return "";
  if (cell.valueType === "select" && cell.options?.[0]) {
    return cell.options[0].displayValue;
  }
  return extractText(cell.content);
}

function normalizeModule(raw: string): string {
  const key = raw
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim();
  if (
    key === "gestion interna" ||
    key === "contabilidad" ||
    key === "talento humano"
  ) {
    return "Gestión interna";
  }
  if (key === "mercadeo" || key === "mercado") {
    return "Mercadeo";
  }
  return raw.trim();
}

function parseRows(rows: MiroRawRow[], clientId: string): MiroTask[] {
  return rows.map((row) => {
    const titulo = getCellValue(row.cells, "Tarea");
    return {
      titulo,
      modulo: normalizeModule(getCellValue(row.cells, "Área")),
      responsable: getCellValue(row.cells, "Responsable"),
      prioridad: getCellValue(row.cells, "Prioridad"),
      fecha: getCellValue(row.cells, "Fecha límite"),
      estado: getCellValue(row.cells, "Estado"),
      fechaIngreso: getCellValue(row.cells, "Fecha ingreso") || undefined,
      rowId: getRowId(clientId, titulo),
    };
  });
}

