export function getMiroTasks(clientId: string): MiroTask[] {
  const rows = RAW_DATA[clientId];
  if (!rows) return [];
  return parseRows(rows, clientId);
}

export function hasMiroData(clientId: string): boolean {
  return clientId in RAW_DATA;
}
